  await expect(page.locator("#campaign-lesson-title")).toContainText("Count All");
  await expect(page.locator("#question-text")).toBeVisible();

  await page.goto("/index.html?mode=infinite");
  await expect(page.locator("#lesson-panel-label")).toContainText("Upgrade Deck");
